// src/ManageOfficers.js
import React, { useState } from 'react';
import './manageOfficers.css';

const ManageOfficers = () => {
  const [officers, setOfficers] = useState([]);
  const [name, setName] = useState('');
  const [role, setRole] = useState('');
  const [email, setEmail] = useState('');

  const handleAddOfficer = (e) => {
    e.preventDefault();
    const newOfficer = {
      id: officers.length + 1, // Simple ID generation
      name,
      role,
      email,
    };
    setOfficers([...officers, newOfficer]);
    // Clear the form fields
    setName('');
    setRole('');
    setEmail('');
  };

  const handleDelete = (id) => {
    setOfficers(officers.filter(officer => officer.id !== id));
  };

  return (
    <div className="manage-officers">
      <h2>Manage Officers</h2>

    <div></div>
      <table className="officers-table">
        <thead>
          <tr>
            <th>ID</th>
            <th>Name</th>
            <th>Role</th>
            <th>Email</th>
            <th>Action</th>
          </tr>
        </thead>
        <tbody>
          {officers.map(officer => (
            <tr key={officer.id}>
              <td>{officer.id}</td>
              <td>{officer.name}</td>
              <td>{officer.role}</td>
              <td>{officer.email}</td>
              <td>
                <button onClick={() => handleDelete(officer.id)}>Delete</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default ManageOfficers;
